import{c as s,Q as t,j as e,m as n}from"./chunks/framework.CBiVa4O3.js";const u=JSON.parse('{"title":"工作流模型","description":"","frontmatter":{},"headers":[],"relativePath":"../gitLearning/19-工作流模型.md","filePath":"../gitLearning/19-工作流模型.md","lastUpdated":1778496697000}'),l={name:"../gitLearning/19-工作流模型.md"};function i(o,a,p,r,d,h){return t(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="工作流模型" tabindex="-1">工作流模型 <a class="header-anchor" href="#工作流模型" aria-label="Permalink to &quot;工作流模型&quot;">​</a></h1><p>到这一篇为止你掌握了 git 的全部&quot;机械操作&quot;——但<strong>怎么和团队配合</strong>是另一个层面的问题。&quot;我们用什么工作流?&quot;——这是任何团队前 3 天必决的事。这一篇讲清楚四种主流工作流(GitFlow / GitHub Flow / Trunk-Based / Release Branch)、每种的适用规模、和<strong>2026 年的工业界趋势:trunk-based 越来越主流,GitFlow 渐被淘汰</strong>。</p><blockquote><p>一句话先记住:<strong>工作流的本质是&quot;分支怎么定义角色&quot;和&quot;什么时候合,合到哪&quot;</strong>。GitFlow 严谨但繁琐;GitHub Flow 简单但少 release 概念;Trunk-Based 极简但要求强大的 CI / 特性开关;Release Branch 适合多版本并行维护的产品。<strong>没有&quot;最好的&quot;工作流——只有&quot;匹配团队规模和产品节奏的&quot;</strong>。</p></blockquote><hr><h2 id="一、gitflow-经典-老派" tabindex="-1">一、GitFlow(经典 / 老派) <a class="header-anchor" href="#一、gitflow-经典-老派" aria-label="Permalink to &quot;一、GitFlow(经典 / 老派)&quot;">​</a></h2><p>2010 年提出,长期是行业标杆。<strong>5 种分支</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main         ──○───○───○──         ← 永远的&quot;已发布版本&quot;</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>develop      ──○─┴─○───○──         ← 集成分支,日常开发</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>feature/*    ──○───○───┘            ← 新功能,从 develop 分,合回 develop</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>release/v1   ───○─┴─○──             ← 发布候选,稳定后合 main + develop</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>hotfix/*     ──○──┴──               ← 线上 bug,从 main 分,合 main + develop</span></span></code></pre></div><h3 id="_1-1-分支角色" tabindex="-1">1.1 分支角色 <a class="header-anchor" href="#_1-1-分支角色" aria-label="Permalink to &quot;1.1 分支角色&quot;">​</a></h3><table tabindex="0"><thead><tr><th>分支</th><th>用途</th><th>来自</th><th>合到</th></tr></thead><tbody><tr><td><code>main</code></td><td>生产代码</td><td>release / hotfix</td><td>(终点)</td></tr><tr><td><code>develop</code></td><td>集成开发</td><td>feature / release / hotfix</td><td>(终点,持续)</td></tr><tr><td><code>feature/xxx</code></td><td>新功能</td><td><code>develop</code></td><td><code>develop</code></td></tr><tr><td><code>release/x.y</code></td><td>发布准备</td><td><code>develop</code></td><td><code>main</code> + <code>develop</code></td></tr><tr><td><code>hotfix/xxx</code></td><td>线上紧急修复</td><td><code>main</code></td><td><code>main</code> + <code>develop</code></td></tr></tbody></table><h3 id="_1-2-优缺点" tabindex="-1">1.2 优缺点 <a class="header-anchor" href="#_1-2-优缺点" aria-label="Permalink to &quot;1.2 优缺点&quot;">​</a></h3><p><strong>优点</strong>:</p><ul><li>严格区分&quot;开发中&quot;和&quot;已发布&quot;</li><li>多版本并行维护好</li><li>分支语义清晰</li></ul><p><strong>缺点</strong>:</p><ul><li>5 种分支学习成本高</li><li>大量 merge commit 污染历史</li><li>feature 分支寿命长,合并冲突多</li><li><strong>跟现代 CI / CD 节奏不符</strong>——CI 强调快速合主、持续交付,GitFlow 强调&quot;先 develop 攒一批,再 release&quot;</li></ul><h3 id="_1-3-适合谁" tabindex="-1">1.3 适合谁 <a class="header-anchor" href="#_1-3-适合谁" aria-label="Permalink to &quot;1.3 适合谁&quot;">​</a></h3><ul><li><strong>2010-2018 主流</strong></li><li>季度 / 半年发布的产品</li><li>桌面软件 / 嵌入式 / SDK——发布周期长</li><li>多版本并行维护(v1.0、v2.0 都要修 bug)</li></ul><blockquote><p><strong>2026 大多数 web / SaaS 团队不再用 GitFlow</strong>——不发版而是持续部署,develop / release 这套抽象已经过度设计。</p></blockquote><hr><h2 id="二、github-flow-简单" tabindex="-1">二、GitHub Flow(简单) <a class="header-anchor" href="#二、github-flow-简单" aria-label="Permalink to &quot;二、GitHub Flow(简单)&quot;">​</a></h2><p>GitHub 内部用,极简:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main      ──○───○───○───○───○──     ← 永远可发布</span></span>
<span class="line"><span>            │       │</span></span>
<span class="line"><span>feature  ───○───○───┘                ← 任何工作都开分支,PR 合回 main</span></span></code></pre></div><h3 id="_2-1-规则" tabindex="-1">2.1 规则 <a class="header-anchor" href="#_2-1-规则" aria-label="Permalink to &quot;2.1 规则&quot;">​</a></h3><ol><li><strong><code>main</code> 永远可发布</strong>——任何时候 deploy main 都不会挂</li><li><strong>任何工作开分支</strong>——名字描述功能(<code>fix-login-bug</code>、<code>refactor-auth</code>)</li><li><strong>PR 是合并的唯一入口</strong>——直接 push main 禁止</li><li><strong>PR review + CI 通过</strong>才能合</li><li><strong>合完立刻 deploy</strong> 或允许 deploy</li></ol><h3 id="_2-2-优缺点" tabindex="-1">2.2 优缺点 <a class="header-anchor" href="#_2-2-优缺点" aria-label="Permalink to &quot;2.2 优缺点&quot;">​</a></h3><p><strong>优点</strong>:</p><ul><li>简单到极致</li><li>适合持续部署</li><li>学习成本低</li></ul><p><strong>缺点</strong>:</p><ul><li>没有 release 概念——不发版本号的产品(SaaS)适合,需要发版本号的产品需要补 tag</li><li>没有 hotfix 概念——所有都从 main 开,但<strong>一旦有&quot;上一个版本要修 bug&quot;就没招</strong></li></ul><h3 id="_2-3-适合谁" tabindex="-1">2.3 适合谁 <a class="header-anchor" href="#_2-3-适合谁" aria-label="Permalink to &quot;2.3 适合谁&quot;">​</a></h3><ul><li><strong>SaaS / Web 应用 / 内部工具</strong></li><li>发布频率高(每周 / 每天)</li><li>单版本(只维护最新版)</li><li>小到中等团队(2-50 人)</li></ul><blockquote><p>GitHub 自己用、Heroku 用、Shopify 用——<strong>只要你的产品&quot;只有一个版本&quot;且持续部署,GitHub Flow 通常够用</strong>。</p></blockquote><hr><h2 id="三、trunk-based-development-主干开发" tabindex="-1">三、Trunk-Based Development(主干开发) <a class="header-anchor" href="#三、trunk-based-development-主干开发" aria-label="Permalink to &quot;三、Trunk-Based Development(主干开发)&quot;">​</a></h2><p>2020 年后大厂推崇的现代工作流。<strong>核心理念</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main      ──○─○─○─○─○─○─○─○─○──     ← 所有 commit 直接合主干</span></span>
<span class="line"><span>              ↑           ↑</span></span>
<span class="line"><span>            短分支         短分支</span></span>
<span class="line"><span>        (1-2 天就合)   (1-2 天就合)</span></span></code></pre></div><h3 id="_3-1-规则" tabindex="-1">3.1 规则 <a class="header-anchor" href="#_3-1-规则" aria-label="Permalink to &quot;3.1 规则&quot;">​</a></h3><ol><li><strong>所有人在 main 或短命分支(&lt; 2 天)上工作</strong></li><li><strong>没有长寿命的 feature 分支</strong></li><li><strong>大功能用 feature flag 控制可见性</strong>——代码合进去了但用户看不到,直到 flag 打开</li><li><strong>强 CI/CD 保障 main 永远绿</strong></li><li><strong>每天合多次</strong>——比 GitHub Flow 更激进</li></ol><h3 id="_3-2-关键技术-特性开关-feature-flag" tabindex="-1">3.2 关键技术:特性开关(feature flag) <a class="header-anchor" href="#_3-2-关键技术-特性开关-feature-flag" aria-label="Permalink to &quot;3.2 关键技术:特性开关(feature flag)&quot;">​</a></h3><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (featureFlags.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NEW_AUTH_FLOW</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> newAuthLogic</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> oldAuthLogic</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>代码合进 main 了,但 flag off → 用户看不到。等 QA 完毕 / 灰度通过 → flag on → 用户看到。</p><p>工具:LaunchDarkly、Statsig、Unleash、自家系统都行。</p><h3 id="_3-3-优缺点" tabindex="-1">3.3 优缺点 <a class="header-anchor" href="#_3-3-优缺点" aria-label="Permalink to &quot;3.3 优缺点&quot;">​</a></h3><p><strong>优点</strong>:</p><ul><li>集成最快,合并冲突最少(没长分支堆积)</li><li>持续交付天然支持</li><li>历史最干净</li></ul><p><strong>缺点</strong>:</p><ul><li>要求强 CI(任何 push 都跑全套测试)</li><li>要求 feature flag 系统</li><li>团队纪律要求高——大改不能&quot;先慢慢做完再合&quot;,必须拆小</li><li>中等以下团队上 feature flag 系统是负担</li></ul><h3 id="_3-4-适合谁" tabindex="-1">3.4 适合谁 <a class="header-anchor" href="#_3-4-适合谁" aria-label="Permalink to &quot;3.4 适合谁&quot;">​</a></h3><ul><li><strong>Google / Meta / Netflix / Spotify 等大厂用</strong></li><li>高频部署的产品(每天 N 次)</li><li>有 feature flag 基建</li><li>团队文化能拆小任务</li></ul><blockquote><p>2020 后<strong>新建团队 / 重构工作流的项目首选 trunk-based</strong>。但需要前期投入(CI、flag 系统)——<strong>小团队没必要硬上</strong>,先用 GitHub Flow,长大了再迁。</p></blockquote><hr><h2 id="四、release-branch-发布分支" tabindex="-1">四、Release Branch(发布分支) <a class="header-anchor" href="#四、release-branch-发布分支" aria-label="Permalink to &quot;四、Release Branch(发布分支)&quot;">​</a></h2><p>适合<strong>多版本并行维护</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main          ──○───○───○───○───○──   ← 持续开发</span></span>
<span class="line"><span>                  │       │</span></span>
<span class="line"><span>release/1.0  ────○─┐──○─┐               ← v1.0 系列</span></span>
<span class="line"><span>                    │     │</span></span>
<span class="line"><span>                    ↓     ↓ </span></span>
<span class="line"><span>                  v1.0.0 v1.0.1</span></span>
<span class="line"><span>                  </span></span>
<span class="line"><span>release/2.0  ─────────○───○───┐</span></span>
<span class="line"><span>                              ↓</span></span>
<span class="line"><span>                            v2.0.0</span></span></code></pre></div><h3 id="_4-1-规则" tabindex="-1">4.1 规则 <a class="header-anchor" href="#_4-1-规则" aria-label="Permalink to &quot;4.1 规则&quot;">​</a></h3><ul><li>main 持续开发(类似 trunk-based 或 GitHub Flow)</li><li>发版时从 main 切一个 <code>release/x.y</code> 分支,只接收 bugfix</li><li>v1.0、v2.0、v3.0 同时维护——分别是各自的 release 分支</li><li>bug 在 main 修了,<strong>cherry-pick 反向传播</strong>到各 release 分支(详见 12 篇)</li></ul><h3 id="_4-2-适合谁" tabindex="-1">4.2 适合谁 <a class="header-anchor" href="#_4-2-适合谁" aria-label="Permalink to &quot;4.2 适合谁&quot;">​</a></h3><ul><li>SDK / 库 / 框架(用户锁定多个版本)</li><li>桌面 / 移动 app(老版本用户多)</li><li>操作系统 / 数据库 / 编译器</li><li>任何&quot;老版本要长期支持&quot;的产品</li></ul><blockquote><p>Linux 内核、Postgres、Node.js 都是这种模式——main 一直跑,但同时维护 v18 / v20 / v22 等多个 LTS 分支。</p></blockquote><hr><h2 id="五、四种工作流对比" tabindex="-1">五、四种工作流对比 <a class="header-anchor" href="#五、四种工作流对比" aria-label="Permalink to &quot;五、四种工作流对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>GitFlow</th><th>GitHub Flow</th><th>Trunk-Based</th><th>Release Branch</th></tr></thead><tbody><tr><td>分支数</td><td>5+</td><td>2(main + features)</td><td>1 + 短分支</td><td>2-N(main + releases)</td></tr><tr><td>学习曲线</td><td>陡</td><td>平</td><td>中(需要 flag)</td><td>中</td></tr><tr><td>发布频率</td><td>季度 / 月</td><td>周 / 天</td><td>天 / 多次</td><td>月 / 季度</td></tr><tr><td>多版本支持</td><td>✅</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>CI 要求</td><td>中</td><td>中</td><td>高</td><td>中</td></tr><tr><td>团队规模</td><td>不限</td><td>小到中</td><td>中到大</td><td>任意</td></tr><tr><td>现代主流度</td><td>↓</td><td>↑</td><td>↑↑</td><td>平</td></tr></tbody></table><hr><h2 id="六、选择决策树" tabindex="-1">六、选择决策树 <a class="header-anchor" href="#六、选择决策树" aria-label="Permalink to &quot;六、选择决策树&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的产品是?</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├─ 持续部署 SaaS / Web 应用</span></span>
<span class="line"><span>│  ├─ 团队 &lt; 20:GitHub Flow</span></span>
<span class="line"><span>│  └─ 团队 &gt; 20 且有 flag 基建:Trunk-Based</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├─ 多版本支持的库 / 框架 / SDK</span></span>
<span class="line"><span>│  → Release Branch</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├─ 桌面 / 移动 / 嵌入式,季度发布</span></span>
<span class="line"><span>│  ├─ 想严谨完整:GitFlow</span></span>
<span class="line"><span>│  └─ 想现代轻巧:Release Branch + 现代 CI</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└─ 不确定 / 新团队</span></span>
<span class="line"><span>   → 从 GitHub Flow 开始,长大再说</span></span></code></pre></div><hr><h2 id="七、常见混合模式" tabindex="-1">七、常见混合模式 <a class="header-anchor" href="#七、常见混合模式" aria-label="Permalink to &quot;七、常见混合模式&quot;">​</a></h2><h3 id="_7-1-github-flow-release-tag" tabindex="-1">7.1 GitHub Flow + Release Tag <a class="header-anchor" href="#_7-1-github-flow-release-tag" aria-label="Permalink to &quot;7.1 GitHub Flow + Release Tag&quot;">​</a></h3><p>不开 release 分支,直接在 main 上打 tag:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tag</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v1.2.0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;...&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tags</span></span></code></pre></div><p><strong>适合 SaaS + 偶尔需要版本号</strong>(给客户报告用、给依赖方做对接)。</p><h3 id="_7-2-trunk-based-release-branch" tabindex="-1">7.2 Trunk-Based + Release Branch <a class="header-anchor" href="#_7-2-trunk-based-release-branch" aria-label="Permalink to &quot;7.2 Trunk-Based + Release Branch&quot;">​</a></h3><p>main 是 trunk,release 分支只在发版时短期存在:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main         ─○─○─○─○─○─○─○─○─</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>release/1.0  ───○ │</span></span>
<span class="line"><span>                  ↓</span></span>
<span class="line"><span>                v1.0.0(打完 tag,release 分支基本不用了)</span></span></code></pre></div><p><strong>适合中等成熟度团队</strong>——主体 trunk-based,但发版时有个&quot;冻结点&quot;做最后 QA。</p><h3 id="_7-3-gitflow-lite" tabindex="-1">7.3 GitFlow Lite <a class="header-anchor" href="#_7-3-gitflow-lite" aria-label="Permalink to &quot;7.3 GitFlow Lite&quot;">​</a></h3><p>GitFlow 的简化版:去掉 develop,只留 main + feature + release + hotfix:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main         ──○────○────○──</span></span>
<span class="line"><span>                │        │</span></span>
<span class="line"><span>feature/*    ──○─┘  ┌────┘</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>hotfix/*     ───────○────</span></span></code></pre></div><p><strong>适合</strong>对 GitFlow 熟悉但团队嫌 develop 累赘的过渡阶段。</p><hr><h2 id="八、protected-branch-工作流的硬执行" tabindex="-1">八、protected branch:工作流的硬执行 <a class="header-anchor" href="#八、protected-branch-工作流的硬执行" aria-label="Permalink to &quot;八、protected branch:工作流的硬执行&quot;">​</a></h2><p>不管你选什么工作流,<strong>用 GitHub / GitLab branch protection 强制执行</strong>:</p><ul><li>禁止直接 push main / develop / release/*</li><li>必须 PR 合并</li><li>PR 必须有 N 人 review approval</li><li>PR 必须 CI 通过</li><li>禁止 force push</li><li>禁止删除分支</li><li>强制签名 commit(高级)</li></ul><blockquote><p>没 branch protection 的工作流是<strong>靠自觉</strong>——长期靠不住。<strong>第一天就配上</strong>,而不是出事故后再补。</p></blockquote><hr><h2 id="九、codeowners-让-review-自动到位" tabindex="-1">九、CODEOWNERS:让 review 自动到位 <a class="header-anchor" href="#九、codeowners-让-review-自动到位" aria-label="Permalink to &quot;九、CODEOWNERS:让 review 自动到位&quot;">​</a></h2><p>GitHub / GitLab 支持 <code>.github/CODEOWNERS</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 各目录的负责人</span></span>
<span class="line"><span>/src/auth/        @alice @bob</span></span>
<span class="line"><span>/src/payment/     @carol</span></span>
<span class="line"><span>/docs/            @dave</span></span>
<span class="line"><span>*                 @team-leads</span></span></code></pre></div><p>PR 改了 <code>src/auth/</code> → 自动 request alice 和 bob review。<strong>比&quot;PR 出来再 @人&quot;靠谱</strong>。</p><hr><h2 id="十、迁移工作流的代价" tabindex="-1">十、迁移工作流的代价 <a class="header-anchor" href="#十、迁移工作流的代价" aria-label="Permalink to &quot;十、迁移工作流的代价&quot;">​</a></h2><p>不要随便迁。每次迁工作流:</p><ul><li>文档要改</li><li>CI 要改</li><li>团队习惯要变</li><li>半年内会反复&quot;我应该往哪合&quot;的混乱</li></ul><p><strong>工作流应该跟产品阶段匹配</strong>:</p><ul><li>0-50 人:GitHub Flow,够了</li><li>50-300 人 + 高频部署:迁 trunk-based,值得</li><li>多版本产品:Release Branch</li><li>稳定 GitFlow 团队:<strong>没必要为了&quot;现代化&quot;而迁</strong>——能跑就行</li></ul><hr><h2 id="十一、踩坑提醒" tabindex="-1">十一、踩坑提醒 <a class="header-anchor" href="#十一、踩坑提醒" aria-label="Permalink to &quot;十一、踩坑提醒&quot;">​</a></h2><ol><li><strong>小团队上 GitFlow</strong>——5 种分支让 3 人团队天天迷路</li><li><strong>大团队 GitHub Flow 没 feature flag</strong>——main 经常爆,大家不敢部署</li><li><strong>trunk-based 没 CI 基建</strong>——直接合主干 = 直接出事故</li><li><strong>Release Branch 不知道 cherry-pick</strong>——hotfix 反向传播全靠人手 patch</li><li><strong>没 branch protection</strong>——工作流纸面规则,实际全靠自觉</li><li><strong>混合工作流没文档化</strong>——新人来了一脸懵</li><li><strong>频繁切工作流</strong>——每次切都是认知成本,半年内事故频发</li><li><strong>以为工作流=用什么命令</strong>——其实是&quot;什么时候做什么决定&quot;</li></ol><hr><p>下一篇:<code>20-Commit-Message与PR规范.md</code>,讲 Conventional Commits 详细规则、PR 描述模板、changelog 自动生成、和团队 review 流程。</p>`,99)])])}const g=s(l,[["render",i]]);export{u as __pageData,g as default};
